// // This module implements a synchronous 4-bit down/up counter with an enable signal. The counter decrements on each clock cycle when the enable signal is high and increments when the enable signal is low. The counter should reset to 0 when the reset signal is high. The reset signal is active high synchronous.
module up_down_counter (
	input clk,
	input reset,
	input enable,
	output reg [3:0] count);

	always @(posedge clk) begin
		if (reset)
			count <= 4'b0000;
		else if (enable)
			count <= count + 1;
		else
			count <= count - 1;
	end

endmodule
